"use client"

import {
  forwardRef,
  useCallback,
  useEffect,
  useLayoutEffect,
  useRef,
  useState,
  type AnimationEvent,
  type CSSProperties,
  type HTMLAttributes,
  type ReactNode,
} from "react"

import "./border-beam.css"

export type BorderBeamSize = "sm" | "md"
export type BorderBeamColorVariant = "colorful" | "mono" | "ocean" | "sunset"

export interface BorderBeamProps
  extends Omit<HTMLAttributes<HTMLDivElement>, "children"> {
  children: ReactNode
  size?: BorderBeamSize
  colorVariant?: BorderBeamColorVariant
  active?: boolean
  borderRadius?: number
  staticColors?: boolean
  duration?: number
  strength?: number
  brightness?: number
  saturation?: number
  hueRange?: number
  onActivate?: () => void
  onDeactivate?: () => void
}

const SIZE_DEFAULT_RADIUS: Record<BorderBeamSize, number> = {
  sm: 18,
  md: 16,
}

export const BorderBeam = forwardRef<HTMLDivElement, BorderBeamProps>(
  function BorderBeam(
    {
      children,
      size = "md",
      colorVariant = "colorful",
      active = true,
      borderRadius,
      staticColors = false,
      duration = 1.96,
      strength = 1,
      brightness = 1.3,
      saturation,
      hueRange = 30,
      className,
      style,
      onActivate,
      onDeactivate,
      onAnimationEnd: consumerOnAnimationEnd,
      ...rest
    },
    forwardedRef
  ) {
    const internalRef = useRef<HTMLDivElement | null>(null)
    const [phase, setPhase] = useState<"idle" | "active" | "fading">(
      active ? "active" : "idle"
    )
    const [detectedRadius, setDetectedRadius] = useState<number | null>(null)

    useLayoutEffect(() => {
      if (borderRadius != null) return
      const child = internalRef.current?.firstElementChild as HTMLElement | null
      if (!child) return
      const r = parseFloat(getComputedStyle(child).borderTopLeftRadius)
      if (!Number.isNaN(r) && r > 0) setDetectedRadius(r)
    }, [borderRadius])

    useEffect(() => {
      if (active && phase !== "active") setPhase("active")
      else if (!active && phase === "active") setPhase("fading")
    }, [active, phase])

    const handleAnimationEnd = useCallback(
      (e: AnimationEvent<HTMLDivElement>) => {
        if (e.target !== e.currentTarget) {
          consumerOnAnimationEnd?.(e)
          return
        }
        const name = e.animationName
        if (name.includes("fade-out")) {
          setPhase("idle")
          onDeactivate?.()
        } else if (name.includes("fade-in")) {
          onActivate?.()
        }
        consumerOnAnimationEnd?.(e)
      },
      [onActivate, onDeactivate, consumerOnAnimationEnd]
    )

    const setRefs = useCallback(
      (node: HTMLDivElement | null) => {
        internalRef.current = node
        if (typeof forwardedRef === "function") forwardedRef(node)
        else if (forwardedRef) forwardedRef.current = node
      },
      [forwardedRef]
    )

    const finalRadius =
      borderRadius ?? detectedRadius ?? SIZE_DEFAULT_RADIUS[size]
    const finalStaticColors = colorVariant === "mono" || staticColors
    const clampedStrength = Math.max(0, Math.min(1, strength))

    const beamStyle: CSSProperties = {
      ...style,
      ["--beam-radius" as string]: `${finalRadius}px`,
      ["--beam-inner-radius" as string]: `${Math.max(0, finalRadius - 1)}px`,
      ["--beam-duration" as string]: `${duration}s`,
      ["--beam-strength" as string]: clampedStrength,
      ["--beam-brightness" as string]: brightness,
      ["--beam-hue-range" as string]: `${hueRange}deg`,
      ...(saturation != null
        ? { ["--beam-saturation" as string]: saturation }
        : {}),
    }

    return (
      <div
        {...rest}
        ref={setRefs}
        className={className}
        style={beamStyle}
        data-beam=""
        data-size={size}
        data-variant={colorVariant}
        data-static-colors={finalStaticColors ? "" : undefined}
        data-active={phase === "active" ? "" : undefined}
        data-fading={phase === "fading" ? "" : undefined}
        onAnimationEnd={handleAnimationEnd}
      >
        {children}
        <div data-beam-bloom />
      </div>
    )
  }
)

BorderBeam.displayName = "BorderBeam"

/*
 * border-beam.css — auto-generated by scripts/generate-css.mjs
 *
 * Refactored from Jakubantalik/border-beam (MIT) into static, registry-native CSS.
 * All per-instance @property names eliminated; multi-instance independence is
 * provided by the CSS standard (each element holds its own value of each
 * inheriting custom property).
 *
 * To tweak palettes or stop positions, edit scripts/generate-css.mjs and rerun
 *   pnpm run generate:css
 */

@property --beam-angle {
  syntax: "<angle>";
  initial-value: 0deg;
  inherits: true;
}
@property --beam-opacity {
  syntax: "<number>";
  initial-value: 0;
  inherits: true;
}

@keyframes beam-spin     { to { --beam-angle: 360deg; } }
@keyframes beam-fade-in  { to { --beam-opacity: 1; } }
@keyframes beam-fade-out { from { --beam-opacity: 1; } to { --beam-opacity: 0; } }
@keyframes beam-hue-shift {
  0%, 100% {
    filter: hue-rotate(calc(var(--beam-hue-range, 30deg) * -1))
            brightness(var(--beam-brightness, 1.3))
            saturate(var(--beam-saturation, 1));
  }
  50% {
    filter: hue-rotate(var(--beam-hue-range, 30deg))
            brightness(var(--beam-brightness, 1.3))
            saturate(var(--beam-saturation, 1));
  }
}

[data-beam] {
  position: relative;
  border-radius: var(--beam-radius, 16px);
  overflow: hidden;
}
[data-beam] [data-beam-bloom] {
  display: none;
}

[data-beam][data-active] {
  animation:
    beam-spin var(--beam-duration, 1.96s) linear infinite,
    beam-fade-in 0.6s ease forwards;
}
[data-beam][data-fading] {
  animation:
    beam-spin var(--beam-duration, 1.96s) linear infinite,
    beam-fade-out 0.5s ease forwards;
}

/* ---- variant overrides for opacity multiplier (mono is half-strength) ---- */

[data-beam][data-variant="mono"] {
  --beam-mono-multiplier: 0.5;
}
[data-beam] {
  --beam-mono-multiplier: 1;
}

/* ---- mappings for the conic theme overlays ---- */

[data-beam] {
  --beam-conic-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 54%, rgba(0, 0, 0, 0.08) 57%, rgba(0, 0, 0, 0.2) 60%, rgba(0, 0, 0, 0.4) 63%, rgba(0, 0, 0, 0.55) 66%, rgba(0, 0, 0, 0.4) 69%, rgba(0, 0, 0, 0.2) 72%, rgba(0, 0, 0, 0.08) 75%, transparent 78%, transparent 100%);
  --beam-bloom-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 58%, rgba(0, 0, 0, 0.02) 62%, rgba(0, 0, 0, 0.08) 65%, rgba(0, 0, 0, 0.2) 67%, rgba(0, 0, 0, 0.4) 69%, rgba(0, 0, 0, 0.6) 70%, rgba(0, 0, 0, 0.6) 70.5%, rgba(0, 0, 0, 0.4) 71.5%, rgba(0, 0, 0, 0.2) 73%, rgba(0, 0, 0, 0.08) 75%, rgba(0, 0, 0, 0.03) 78%, transparent 82%);
}
.dark [data-beam] {
  --beam-conic-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 54%, rgba(255, 255, 255, 0.1) 57%, rgba(255, 255, 255, 0.3) 60%, rgba(255, 255, 255, 0.6) 63%, rgba(255, 255, 255, 0.75) 66%, rgba(255, 255, 255, 0.6) 69%, rgba(255, 255, 255, 0.3) 72%, rgba(255, 255, 255, 0.1) 75%, transparent 78%, transparent 100%);
  --beam-bloom-overlay: conic-gradient(from var(--beam-angle), transparent 0%, transparent 58%, rgba(255, 255, 255, 0.03) 62%, rgba(255, 255, 255, 0.08) 65%, rgba(255, 255, 255, 0.2) 67%, rgba(255, 255, 255, 0.45) 69%, rgba(255, 255, 255, 0.85) 70%, rgba(255, 255, 255, 0.85) 70.5%, rgba(255, 255, 255, 0.45) 71.5%, rgba(255, 255, 255, 0.2) 73%, rgba(255, 255, 255, 0.08) 75%, rgba(255, 255, 255, 0.03) 78%, transparent 82%);
}

/* ---- per-variant color gradients (theme-independent) ---- */

[data-beam][data-size="md"][data-variant="colorful"] {
  --beam-color-gradient: radial-gradient(ellipse 70px 40px at 33% -7.4%, rgb(255, 50, 100), transparent),
      radial-gradient(ellipse 60px 35px at 12% -5%, rgb(40, 140, 255), transparent),
      radial-gradient(ellipse 40px 70px at 2.1% 68.3%, rgb(50, 200, 80), transparent),
      radial-gradient(ellipse 20px 35px at 2.1% 68.3%, rgb(30, 185, 170), transparent),
      radial-gradient(ellipse 180px 32px at 74.4% 100%, rgb(100, 70, 255), transparent),
      radial-gradient(ellipse 85px 26px at 55% 100%, rgb(40, 140, 255), transparent),
      radial-gradient(ellipse 74px 32px at 93.9% 0%, rgb(255, 120, 40), transparent),
      radial-gradient(ellipse 26px 42px at 100% 27.1%, rgb(240, 50, 180), transparent),
      radial-gradient(ellipse 52px 48px at 100% 27.1%, rgb(180, 40, 240), transparent);
  --beam-inner-gradient: radial-gradient(ellipse 63px 36px at 33% -7.4%, rgba(255, 50, 100, 0.45), transparent),
      radial-gradient(ellipse 54px 32px at 12% -5%, rgba(40, 140, 255, 0.45), transparent),
      radial-gradient(ellipse 36px 63px at 2.1% 68.3%, rgba(50, 200, 80, 0.45), transparent),
      radial-gradient(ellipse 18px 32px at 2.1% 68.3%, rgba(30, 185, 170, 0.45), transparent),
      radial-gradient(ellipse 162px 29px at 74.4% 100%, rgba(100, 70, 255, 0.45), transparent),
      radial-gradient(ellipse 77px 23px at 55% 100%, rgba(40, 140, 255, 0.45), transparent),
      radial-gradient(ellipse 67px 29px at 93.9% 0%, rgba(255, 120, 40, 0.45), transparent),
      radial-gradient(ellipse 23px 38px at 100% 27.1%, rgba(240, 50, 180, 0.45), transparent),
      radial-gradient(ellipse 47px 43px at 100% 27.1%, rgba(180, 40, 240, 0.45), transparent);
}
[data-beam][data-size="sm"][data-variant="colorful"] {
  --beam-color-gradient: radial-gradient(ellipse 9px 18px at 2% 68%, rgb(50, 200, 80), transparent),
      radial-gradient(ellipse 4px 8px at 2% 68%, rgb(30, 185, 170), transparent),
