[data-beam][data-size="md"][data-variant="mono"] {
  --beam-color-gradient: radial-gradient(ellipse 70px 40px at 33% -7.4%, rgb(180, 180, 180), transparent),
      radial-gradient(ellipse 60px 35px at 12% -5%, rgb(140, 140, 140), transparent),
      radial-gradient(ellipse 40px 70px at 2.1% 68.3%, rgb(160, 160, 160), transparent),
      radial-gradient(ellipse 20px 35px at 2.1% 68.3%, rgb(130, 130, 130), transparent),
      radial-gradient(ellipse 180px 32px at 74.4% 100%, rgb(170, 170, 170), transparent),
      radial-gradient(ellipse 85px 26px at 55% 100%, rgb(150, 150, 150), transparent),
      radial-gradient(ellipse 74px 32px at 93.9% 0%, rgb(190, 190, 190), transparent),
      radial-gradient(ellipse 26px 42px at 100% 27.1%, rgb(145, 145, 145), transparent),
      radial-gradient(ellipse 52px 48px at 100% 27.1%, rgb(165, 165, 165), transparent);
  --beam-inner-gradient: radial-gradient(ellipse 63px 36px at 33% -7.4%, rgba(180, 180, 180, 0.225), transparent),
      radial-gradient(ellipse 54px 32px at 12% -5%, rgba(140, 140, 140, 0.225), transparent),
      radial-gradient(ellipse 36px 63px at 2.1% 68.3%, rgba(160, 160, 160, 0.225), transparent),
      radial-gradient(ellipse 18px 32px at 2.1% 68.3%, rgba(130, 130, 130, 0.225), transparent),
      radial-gradient(ellipse 162px 29px at 74.4% 100%, rgba(170, 170, 170, 0.225), transparent),
      radial-gradient(ellipse 77px 23px at 55% 100%, rgba(150, 150, 150, 0.225), transparent),
      radial-gradient(ellipse 67px 29px at 93.9% 0%, rgba(190, 190, 190, 0.225), transparent),
      radial-gradient(ellipse 23px 38px at 100% 27.1%, rgba(145, 145, 145, 0.225), transparent),
      radial-gradient(ellipse 47px 43px at 100% 27.1%, rgba(165, 165, 165, 0.225), transparent);
}
[data-beam][data-size="sm"][data-variant="mono"] {
  --beam-color-gradient: radial-gradient(ellipse 9px 18px at 2% 68%, rgb(160, 160, 160), transparent),
      radial-gradient(ellipse 4px 8px at 2% 68%, rgb(140, 140, 140), transparent),
      radial-gradient(ellipse 59px 9px at 72% -3%, rgb(180, 180, 180), transparent),
      radial-gradient(ellipse 42px 7px at 74% 100%, rgb(150, 150, 150), transparent),
      radial-gradient(ellipse 10px 17px at 100% 27%, rgb(170, 170, 170), transparent),
      radial-gradient(ellipse 10px 18px at 100% 27%, rgb(155, 155, 155), transparent),
      radial-gradient(ellipse 5px 10px at 100% 27%, rgb(145, 145, 145), transparent),
      radial-gradient(ellipse 11px 12px at 100% 27%, rgb(165, 165, 165), transparent);
  --beam-inner-gradient: radial-gradient(ellipse 9px 18px at 2% 68%, rgba(160, 160, 160, 0.25), transparent),
      radial-gradient(ellipse 4px 8px at 2% 68%, rgba(140, 140, 140, 0.22), transparent),
      radial-gradient(ellipse 59px 9px at 72% -3%, rgba(180, 180, 180, 0.17), transparent),
      radial-gradient(ellipse 42px 7px at 74% 100%, rgba(150, 150, 150, 0.17), transparent),
      radial-gradient(ellipse 10px 17px at 100% 27%, rgba(170, 170, 170, 0.15), transparent),
      radial-gradient(ellipse 10px 18px at 100% 27%, rgba(155, 155, 155, 0.20), transparent),
      radial-gradient(ellipse 5px 10px at 100% 27%, rgba(145, 145, 145, 0.15), transparent),
      radial-gradient(ellipse 11px 12px at 100% 27%, rgba(165, 165, 165, 0.15), transparent);
}

[data-beam][data-size="md"][data-variant="ocean"] {
  --beam-color-gradient: radial-gradient(ellipse 70px 40px at 33% -7.4%, rgb(100, 80, 220), transparent),
      radial-gradient(ellipse 60px 35px at 12% -5%, rgb(60, 120, 255), transparent),
      radial-gradient(ellipse 40px 70px at 2.1% 68.3%, rgb(80, 100, 200), transparent),
      radial-gradient(ellipse 20px 35px at 2.1% 68.3%, rgb(50, 140, 220), transparent),
      radial-gradient(ellipse 180px 32px at 74.4% 100%, rgb(120, 80, 255), transparent),
      radial-gradient(ellipse 85px 26px at 55% 100%, rgb(70, 130, 255), transparent),
      radial-gradient(ellipse 74px 32px at 93.9% 0%, rgb(140, 100, 240), transparent),
      radial-gradient(ellipse 26px 42px at 100% 27.1%, rgb(90, 110, 230), transparent),
      radial-gradient(ellipse 52px 48px at 100% 27.1%, rgb(130, 70, 255), transparent);
  --beam-inner-gradient: radial-gradient(ellipse 63px 36px at 33% -7.4%, rgba(100, 80, 220, 0.45), transparent),
      radial-gradient(ellipse 54px 32px at 12% -5%, rgba(60, 120, 255, 0.45), transparent),
      radial-gradient(ellipse 36px 63px at 2.1% 68.3%, rgba(80, 100, 200, 0.45), transparent),
      radial-gradient(ellipse 18px 32px at 2.1% 68.3%, rgba(50, 140, 220, 0.45), transparent),
      radial-gradient(ellipse 162px 29px at 74.4% 100%, rgba(120, 80, 255, 0.45), transparent),
      radial-gradient(ellipse 77px 23px at 55% 100%, rgba(70, 130, 255, 0.45), transparent),
      radial-gradient(ellipse 67px 29px at 93.9% 0%, rgba(140, 100, 240, 0.45), transparent),
      radial-gradient(ellipse 23px 38px at 100% 27.1%, rgba(90, 110, 230, 0.45), transparent),
      radial-gradient(ellipse 47px 43px at 100% 27.1%, rgba(130, 70, 255, 0.45), transparent);
}
[data-beam][data-size="sm"][data-variant="ocean"] {
  --beam-color-gradient: radial-gradient(ellipse 9px 18px at 2% 68%, rgb(60, 140, 200), transparent),
      radial-gradient(ellipse 4px 8px at 2% 68%, rgb(50, 120, 180), transparent),
      radial-gradient(ellipse 59px 9px at 72% -3%, rgb(100, 80, 220), transparent),
      radial-gradient(ellipse 42px 7px at 74% 100%, rgb(80, 100, 255), transparent),
      radial-gradient(ellipse 10px 17px at 100% 27%, rgb(120, 70, 240), transparent),
      radial-gradient(ellipse 10px 18px at 100% 27%, rgb(90, 80, 220), transparent),
      radial-gradient(ellipse 5px 10px at 100% 27%, rgb(70, 110, 255), transparent),
      radial-gradient(ellipse 11px 12px at 100% 27%, rgb(110, 90, 230), transparent);
  --beam-inner-gradient: radial-gradient(ellipse 9px 18px at 2% 68%, rgba(60, 140, 200, 0.5), transparent),
      radial-gradient(ellipse 4px 8px at 2% 68%, rgba(50, 120, 180, 0.45), transparent),
      radial-gradient(ellipse 59px 9px at 72% -3%, rgba(100, 80, 220, 0.35), transparent),
      radial-gradient(ellipse 42px 7px at 74% 100%, rgba(80, 100, 255, 0.35), transparent),
      radial-gradient(ellipse 10px 17px at 100% 27%, rgba(120, 70, 240, 0.3), transparent),
      radial-gradient(ellipse 10px 18px at 100% 27%, rgba(90, 80, 220, 0.4), transparent),
